// ===========================================
// Abideen.dev — Portfolio JavaScript
// ===========================================

document.addEventListener('DOMContentLoaded', function () {

    // ---- Loading Screen ----
    const loadingScreen = document.getElementById('loading-screen');
    if (loadingScreen) {
        window.addEventListener('load', function () {
            setTimeout(() => {
                loadingScreen.classList.add('loaded');
            }, 600);
        });
    }

    // ---- Navbar Scroll Effect ----
    const navbar = document.getElementById('main-navbar');
    if (navbar) {
        const handleNavScroll = () => {
            if (window.scrollY > 50) {
                navbar.classList.add('scrolled');
            } else {
                navbar.classList.remove('scrolled');
            }
        };
        window.addEventListener('scroll', handleNavScroll, { passive: true });
        handleNavScroll();
    }

    // ---- Dark/Light Theme Toggle ----
    const themeToggle = document.getElementById('theme-toggle');
    const themeIcon = document.getElementById('theme-icon');
    const html = document.documentElement;

    const savedTheme = localStorage.getItem('theme') || 'dark';
    html.setAttribute('data-bs-theme', savedTheme);
    updateThemeIcon(savedTheme);

    if (themeToggle) {
        themeToggle.addEventListener('click', function () {
            const currentTheme = html.getAttribute('data-bs-theme');
            const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
            html.setAttribute('data-bs-theme', newTheme);
            localStorage.setItem('theme', newTheme);
            updateThemeIcon(newTheme);
        });
    }

    function updateThemeIcon(theme) {
        if (themeIcon) {
            themeIcon.className = theme === 'dark' ? 'bi bi-sun' : 'bi bi-moon-stars';
        }
    }

    // ---- Typing Animation ----
    const typingElement = document.getElementById('typing-text');
    if (typingElement) {
        const words = JSON.parse(typingElement.dataset.words || '["Full-Stack Developer"]');
        let wordIndex = 0;
        let charIndex = 0;
        let isDeleting = false;

        function typeEffect() {
            const currentWord = words[wordIndex];

            if (isDeleting) {
                typingElement.textContent = currentWord.substring(0, charIndex - 1);
                charIndex--;
            } else {
                typingElement.textContent = currentWord.substring(0, charIndex + 1);
                charIndex++;
            }

            let typeSpeed = isDeleting ? 50 : 100;

            if (!isDeleting && charIndex === currentWord.length) {
                typeSpeed = 2000;
                isDeleting = true;
            } else if (isDeleting && charIndex === 0) {
                isDeleting = false;
                wordIndex = (wordIndex + 1) % words.length;
                typeSpeed = 500;
            }

            setTimeout(typeEffect, typeSpeed);
        }

        typeEffect();
    }

    // ---- Scroll Reveal (IntersectionObserver) ----
    const revealElements = document.querySelectorAll('.reveal, .reveal-left, .reveal-right, .reveal-scale');
    const revealObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('is-visible');
                revealObserver.unobserve(entry.target);
            }
        });
    }, { threshold: 0.15, rootMargin: '0px 0px -50px 0px' });

    revealElements.forEach(el => revealObserver.observe(el));

    // ---- Animated Counters ----
    const counters = document.querySelectorAll('.stat-number');
    const counterObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const target = parseInt(entry.target.dataset.target);
                let current = 0;
                const increment = target / 60;

                const updateCounter = () => {
                    current += increment;
                    if (current < target) {
                        entry.target.textContent = Math.ceil(current);
                        requestAnimationFrame(updateCounter);
                    } else {
                        entry.target.textContent = target + (entry.target.dataset.suffix || '');
                    }
                };

                updateCounter();
                counterObserver.unobserve(entry.target);
            }
        });
    }, { threshold: 0.5 });

    counters.forEach(counter => counterObserver.observe(counter));

    // ---- Skills Progress Bars ----
    const skillBars = document.querySelectorAll('.skill-progress-bar');
    const skillObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const target = entry.target.dataset.progress;
                entry.target.style.width = target + '%';
                skillObserver.unobserve(entry.target);
            }
        });
    }, { threshold: 0.3 });

    skillBars.forEach(bar => skillObserver.observe(bar));

    // ---- Project Filtering ----
    const filterButtons = document.querySelectorAll('.filter-btn');
    const projectItems = document.querySelectorAll('.project-item');

    filterButtons.forEach(btn => {
        btn.addEventListener('click', function () {
            const filter = this.dataset.filter;

            filterButtons.forEach(b => b.classList.remove('active'));
            this.classList.add('active');

            projectItems.forEach(item => {
                if (filter === 'all' || item.dataset.category === filter) {
                    item.style.display = '';
                    setTimeout(() => {
                        item.style.opacity = '1';
                        item.style.transform = 'scale(1)';
                    }, 50);
                } else {
                    item.style.opacity = '0';
                    item.style.transform = 'scale(0.8)';
                    setTimeout(() => {
                        item.style.display = 'none';
                    }, 300);
                }
            });
        });
    });

    // ---- Lightbox ----
    const lightbox = document.getElementById('lightbox');
    const lightboxImage = document.getElementById('lightbox-image');
    const lightboxClose = document.getElementById('lightbox-close');
    const lightboxPrev = document.getElementById('lightbox-prev');
    const lightboxNext = document.getElementById('lightbox-next');

    let currentImageIndex = 0;
    let imageList = [];

    document.querySelectorAll('[data-lightbox]').forEach((trigger, index) => {
        imageList.push(trigger.getAttribute('href'));

        trigger.addEventListener('click', function (e) {
            e.preventDefault();
            currentImageIndex = imageList.indexOf(this.getAttribute('href'));
            showLightbox();
        });
    });

    function showLightbox() {
        if (lightbox && lightboxImage) {
            lightboxImage.src = imageList[currentImageIndex];
            lightbox.classList.add('show');
            lightbox.style.display = 'flex';
            document.body.style.overflow = 'hidden';
        }
    }

    function hideLightbox() {
        if (lightbox) {
            lightbox.classList.remove('show');
            lightbox.style.display = 'none';
            document.body.style.overflow = '';
        }
    }

    function showNext() {
        currentImageIndex = (currentImageIndex + 1) % imageList.length;
        showLightbox();
    }

    function showPrev() {
        currentImageIndex = (currentImageIndex - 1 + imageList.length) % imageList.length;
        showLightbox();
    }

    if (lightboxClose) lightboxClose.addEventListener('click', hideLightbox);
    if (lightboxNext) lightboxNext.addEventListener('click', showNext);
    if (lightboxPrev) lightboxPrev.addEventListener('click', showPrev);

    if (lightbox) {
        lightbox.addEventListener('click', function (e) {
            if (e.target === lightbox) hideLightbox();
        });
    }

    document.addEventListener('keydown', function (e) {
        if (lightbox && lightbox.classList.contains('show')) {
            if (e.key === 'Escape') hideLightbox();
            if (e.key === 'ArrowRight') showNext();
            if (e.key === 'ArrowLeft') showPrev();
        }
    });

    // ---- Back to Top Button ----
    const backToTop = document.getElementById('back-to-top');
    if (backToTop) {
        window.addEventListener('scroll', function () {
            if (window.scrollY > 400) {
                backToTop.classList.add('visible');
            } else {
                backToTop.classList.remove('visible');
            }
        }, { passive: true });

        backToTop.addEventListener('click', function () {
            window.scrollTo({ top: 0, behavior: 'smooth' });
        });
    }

    // ---- Smooth Scroll for Anchor Links ----
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
            const href = this.getAttribute('href');
            if (href === '#' || href === '#!') return;

            const target = document.querySelector(href);
            if (target) {
                e.preventDefault();
                const offset = 80;
                const targetPosition = target.getBoundingClientRect().top + window.scrollY - offset;
                window.scrollTo({ top: targetPosition, behavior: 'smooth' });

                // Close mobile navbar
                const navCollapse = document.querySelector('.navbar-collapse');
                if (navCollapse && navCollapse.classList.contains('show')) {
                    const bsCollapse = bootstrap.Collapse.getInstance(navCollapse);
                    if (bsCollapse) bsCollapse.hide();
                }
            }
        });
    });

    // ---- Active Nav Link on Scroll ----
    const sections = document.querySelectorAll('section[id]');
    const navLinks = document.querySelectorAll('.navbar-custom .nav-link');

    window.addEventListener('scroll', function () {
        const scrollPos = window.scrollY + 100;

        sections.forEach(section => {
            const top = section.offsetTop;
            const height = section.offsetHeight;
            const id = section.getAttribute('id');

            if (scrollPos >= top && scrollPos < top + height) {
                navLinks.forEach(link => {
                    link.classList.remove('active');
                    if (link.getAttribute('href') === '#' + id) {
                        link.classList.add('active');
                    }
                });
            }
        });
    }, { passive: true });

    // ---- Contact Form AJAX Submission ----
    const contactForm = document.getElementById('contact-form');
    if (contactForm) {
        contactForm.addEventListener('submit', function (e) {
            e.preventDefault();

            const submitBtn = contactForm.querySelector('button[type="submit"]');
            const originalText = submitBtn.innerHTML;
            submitBtn.disabled = true;
            submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Sending...';

            const formData = new FormData(contactForm);

            fetch(contactForm.action, {
                method: 'POST',
                headers: {
                    'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').getAttribute('content'),
                    'Accept': 'application/json',
                },
                body: formData,
            })
            .then(response => response.json())
            .then(data => {
                if (data.success) {
                    showToast('Message sent successfully! I\'ll get back to you soon.', 'success');
                    contactForm.reset();
                } else {
                    const errors = data.errors || {};
                    const firstError = Object.values(errors)[0];
                    showToast(firstError || 'Something went wrong. Please try again.', 'error');
                }
            })
            .catch(() => {
                showToast('Something went wrong. Please try again.', 'error');
            })
            .finally(() => {
                submitBtn.disabled = false;
                submitBtn.innerHTML = originalText;
            });
        });
    }

    // ---- Toast Notifications ----
    window.showToast = function (message, type = 'success') {
        const toastContainer = document.getElementById('toast-container');
        if (!toastContainer) return;

        const toastId = 'toast-' + Date.now();
        const iconMap = {
            success: 'bi-check-circle-fill',
            error: 'bi-x-circle-fill',
            warning: 'bi-exclamation-triangle-fill',
            info: 'bi-info-circle-fill',
        };

        const colorMap = {
            success: 'text-success',
            error: 'text-danger',
            warning: 'text-warning',
            info: 'text-info',
        };

        const toastHTML = `
            <div id="${toastId}" class="toast align-items-center" role="alert" aria-live="assertive" aria-atomic="true">
                <div class="d-flex">
                    <div class="toast-body">
                        <i class="bi ${iconMap[type]} ${colorMap[type]} me-2"></i>
                        ${message}
                    </div>
                    <button type="button" class="btn-close me-2 m-auto" data-bs-dismiss="toast" aria-label="Close"></button>
                </div>
            </div>
        `;

        toastContainer.insertAdjacentHTML('beforeend', toastHTML);
        const toastEl = document.getElementById(toastId);
        const bsToast = new bootstrap.Toast(toastEl, { delay: 5000 });
        bsToast.show();

        toastEl.addEventListener('hidden.bs.toast', () => toastEl.remove());
    };

    // ---- Testimonials Carousel ----
    const testimonialCarousel = document.getElementById('testimonialCarousel');
    if (testimonialCarousel) {
        new bootstrap.Carousel(testimonialCarousel, {
            interval: 5000,
            ride: 'carousel',
            pause: 'hover',
        });
    }

    // ---- Project Cost Calculator ----
    const calcSection = document.getElementById('calculator');
    if (calcSection) {
        const projectTypeBtns = calcSection.querySelectorAll('.project-type-btn');
        const pageCountSlider = document.getElementById('page-count');
        const pageCountDisplay = document.getElementById('page-count-display');
        const featureCheckboxes = calcSection.querySelectorAll('.feature-checkbox');
        const totalCostEl = document.getElementById('total-cost');
        const resetBtn = document.getElementById('calc-reset-btn');
        const getQuoteBtn = document.getElementById('get-quote-btn');
        const breakdownType = document.getElementById('breakdown-type');
        const breakdownTypeCost = document.getElementById('breakdown-type-cost');
        const breakdownPagesText = document.getElementById('breakdown-pages-text');
        const breakdownPagesCost = document.getElementById('breakdown-pages-cost');
        const breakdownFeaturesRow = document.getElementById('breakdown-features-row');
        const breakdownFeaturesCost = document.getElementById('breakdown-features-cost');

        const PAGE_RATE = parseInt(pageCountSlider.dataset.perPage) || 10000;
        const INCLUDED_PAGES = parseInt(pageCountSlider.dataset.included) || 5;

        let currentType = projectTypeBtns[0].dataset.type;
        let currentBase = parseInt(projectTypeBtns[0].dataset.base) || 50000;
        let currentTypeName = projectTypeBtns[0].querySelector('span').textContent;

        function formatNaira(amount) {
            return '\u20a6' + amount.toLocaleString('en-US');
        }

        function calculateCost() {
            const pages = parseInt(pageCountSlider.value);
            const extraPages = Math.max(0, pages - INCLUDED_PAGES);
            const pagesCost = extraPages * PAGE_RATE;

            let featuresCost = 0;
            featureCheckboxes.forEach(cb => {
                if (cb.checked) featuresCost += parseInt(cb.dataset.cost);
            });

            const total = currentBase + pagesCost + featuresCost;
            totalCostEl.textContent = formatNaira(total);

            breakdownType.textContent = currentTypeName;
            breakdownTypeCost.textContent = formatNaira(currentBase);

            breakdownPagesText.textContent = extraPages > 0
                ? 'Extra Pages (' + extraPages + ')'
                : 'Extra Pages (0)';
            breakdownPagesCost.textContent = formatNaira(pagesCost);

            if (featuresCost > 0) {
                breakdownFeaturesRow.style.display = 'flex';
                breakdownFeaturesCost.textContent = formatNaira(featuresCost);
            } else {
                breakdownFeaturesRow.style.display = 'none';
            }
        }

        projectTypeBtns.forEach(btn => {
            btn.addEventListener('click', function () {
                projectTypeBtns.forEach(b => b.classList.remove('active'));
                this.classList.add('active');
                currentType = this.dataset.type;
                currentBase = parseInt(this.dataset.base);
                currentTypeName = this.querySelector('span').textContent;
                calculateCost();
            });
        });

        pageCountSlider.addEventListener('input', function () {
            pageCountDisplay.textContent = this.value;
            calculateCost();
        });

        featureCheckboxes.forEach(cb => {
            cb.addEventListener('change', calculateCost);
        });

        resetBtn.addEventListener('click', function () {
            projectTypeBtns.forEach(b => b.classList.remove('active'));
            projectTypeBtns[0].classList.add('active');
            currentType = projectTypeBtns[0].dataset.type;
            currentBase = parseInt(projectTypeBtns[0].dataset.base);
            currentTypeName = projectTypeBtns[0].querySelector('span').textContent;

            pageCountSlider.value = 1;
            pageCountDisplay.textContent = '1';

            featureCheckboxes.forEach(cb => cb.checked = false);

            calculateCost();

            if (window.showToast) {
                showToast('Calculator has been reset.', 'info');
            }
        });

        getQuoteBtn.addEventListener('click', function () {
            const pages = parseInt(pageCountSlider.value);
            const selectedFeatures = [];
            featureCheckboxes.forEach(cb => {
                if (cb.checked) {
                    selectedFeatures.push(cb.parentElement.textContent.trim());
                }
            });

            const subjectField = document.querySelector('#contact-form input[name="subject"]');
            const messageField = document.querySelector('#contact-form textarea[name="message"]');

            if (subjectField) {
                subjectField.value = 'Project Quote Request — ' + currentTypeName;
            }

            if (messageField) {
                let msg = 'Hi Abideen,\n\nI would like to get a quote for the following project:\n\n';
                msg += '• Project Type: ' + currentTypeName + '\n';
                msg += '• Number of Pages: ' + pages + '\n';
                if (selectedFeatures.length > 0) {
                    msg += '• Extra Features: ' + selectedFeatures.join(', ') + '\n';
                }
                msg += '• Estimated Budget: ' + totalCostEl.textContent + '\n\n';
                msg += 'Please get back to me with a detailed quote. Thank you!';
                messageField.value = msg;
            }

            const contactSection = document.getElementById('contact');
            if (contactSection) {
                const offset = 80;
                const targetPosition = contactSection.getBoundingClientRect().top + window.scrollY - offset;
                window.scrollTo({ top: targetPosition, behavior: 'smooth' });
            }

            if (window.showToast) {
                showToast('Quote details filled in the contact form below!', 'success');
            }
        });

        calculateCost();
    }
});

// ===========================================
// Abideen.dev — Main Stylesheet
// ===========================================

// Bootstrap 5
@import 'bootstrap/scss/bootstrap';

// Bootstrap Icons (imported via JS for proper font file resolution)

// Custom Variables
@import 'variables';

// Animations
@import 'animations';

// Components
@import 'components';

// ===========================================
// Abideen.dev — Custom SCSS Variables
// ===========================================

// Accent Colors
$gold: #d4af37;
$gold-light: #e8c547;
$gold-dark: #b8941f;
$blue: #3b82f6;
$blue-light: #60a5fa;
$blue-dark: #2563eb;

// Dark Theme Colors
$dark-bg: #0a0a0a;
$dark-bg-alt: #121212;
$dark-card: #1a1a1a;
$dark-border: #2a2a2a;
$dark-text: #e0e0e0;
$dark-text-muted: #a0a0a0;

// Light Theme Colors
$light-bg: #f8f9fa;
$light-bg-alt: #ffffff;
$light-card: #ffffff;
$light-border: #e0e0e0;
$light-text: #1a1a1a;
$light-text-muted: #6c757d;

// Typography
$font-family-base: 'Inter', 'Segoe UI', system-ui, -apple-system, sans-serif;
$font-family-heading: 'Poppins', 'Inter', system-ui, sans-serif;
$font-family-code: 'JetBrains Mono', 'Fira Code', monospace;

// Shadows
$shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.15);
$shadow-md: 0 4px 20px rgba(0, 0, 0, 0.25);
$shadow-lg: 0 8px 30px rgba(0, 0, 0, 0.35);
$shadow-gold: 0 4px 20px rgba(212, 175, 55, 0.25);
$shadow-blue: 0 4px 20px rgba(59, 130, 246, 0.25);

// Transitions
$transition-base: all 0.3s ease;
$transition-slow: all 0.5s ease;
$transition-fast: all 0.15s ease;

// Border radius
$radius-sm: 8px;
$radius-md: 12px;
$radius-lg: 20px;
$radius-pill: 50rem;

// Bootstrap overrides
$primary: $gold;
$secondary: $blue;
$body-bg-dark: $dark-bg;
$body-color-dark: $dark-text;
$border-radius: $radius-sm;
$border-radius-sm: $radius-sm;
$border-radius-lg: $radius-md;

// ===========================================
// Abideen.dev — Custom Components
// ===========================================

$dark-card-alt: #161616;

// ---- CSS Custom Properties (Theming) ----
:root {
    --accent-gold: #{$gold};
    --accent-gold-light: #{$gold-light};
    --accent-blue: #{$blue};
    --accent-blue-light: #{$blue-light};
    --gradient-gold: linear-gradient(135deg, #{$gold} 0%, #{$gold-light} 50%, #{$gold} 100%);
    --gradient-blue: linear-gradient(135deg, #{$blue} 0%, #{$blue-light} 100%);
    --gradient-accent: linear-gradient(135deg, #{$gold} 0%, #{$blue} 100%);
    --gradient-text: linear-gradient(135deg, #{$gold} 0%, #{$gold-light} 50%, #{$blue-light} 100%);
}

// ---- Body & Base ----
body {
    font-family: $font-family-base;
    scroll-behavior: smooth;
    overflow-x: hidden;
    max-width: 100vw;
}

h1, h2, h3, h4, h5, h6 {
    font-family: $font-family-heading;
    font-weight: 700;
}

::selection {
    background: rgba($gold, 0.3);
    color: $gold;
}

// Scrollbar
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: $dark-bg-alt;
}

::-webkit-scrollbar-thumb {
    background: $dark-border;
    border-radius: 4px;

    &:hover {
        background: $gold;
    }
}

// ---- Gradient Text ----
.text-gradient {
    background: var(--gradient-text);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.text-gradient-gold {
    background: var(--gradient-gold);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

// ---- Accent Buttons ----
.btn-gold {
    background: var(--gradient-gold);
    color: #000;
    border: none;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        color: #000;
        box-shadow: $shadow-gold;
        transform: translateY(-2px);
    }
}

.btn-blue {
    background: var(--gradient-blue);
    color: #fff;
    border: none;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        color: #fff;
        box-shadow: $shadow-blue;
        transform: translateY(-2px);
    }
}

.btn-outline-gold {
    border: 2px solid $gold;
    color: $gold;
    background: transparent;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        background: $gold;
        color: #000;
        box-shadow: $shadow-gold;
    }
}

// ---- Loading Screen ----
.loading-screen {
    position: fixed;
    inset: 0;
    z-index: 9999;
    display: flex;
    align-items: center;
    justify-content: center;
    background: $dark-bg;
    transition: opacity 0.6s ease, visibility 0.6s ease;

    &.loaded {
        opacity: 0;
        visibility: hidden;
    }

    .loader {
        width: 60px;
        height: 60px;
        border: 4px solid $dark-border;
        border-top-color: $gold;
        border-radius: 50%;
        animation: spin 0.8s linear infinite;
    }

    .loader-text {
        margin-top: 1.5rem;
        font-family: $font-family-heading;
        font-size: 1.5rem;
        font-weight: 700;
        letter-spacing: 2px;
    }
}

// ---- Navbar ----
.navbar-custom {
    transition: $transition-slow;
    padding: 1.2rem 0;
    overflow-x: hidden;

    &.scrolled {
        padding: 0.5rem 0;
        backdrop-filter: blur(12px);
    }

    .navbar-brand {
        font-family: $font-family-heading;
        font-weight: 800;
        font-size: 1.5rem;
        letter-spacing: -0.5px;
        white-space: nowrap;
    }

    .navbar-toggler {
        padding: 0.25rem 0.5rem;
        flex-shrink: 0;
    }

    .nav-link {
        position: relative;
        font-weight: 500;
        transition: $transition-fast;
        padding: 0.5rem 1rem;

        &::after {
            content: '';
            position: absolute;
            bottom: 0;
            left: 50%;
            width: 0;
            height: 2px;
            background: var(--gradient-gold);
            transition: width 0.3s ease;
            transform: translateX(-50%);
        }

        &:hover::after,
        &.active::after {
            width: 70%;
        }
    }
}

// ---- Hero Section ----
.hero-section {
    position: relative;
    min-height: 100vh;
    display: flex;
    align-items: center;
    overflow-x: hidden;

    .hero-bg-gradient {
        position: absolute;
        inset: 0;
        background: radial-gradient(circle at 20% 50%, rgba($gold, 0.08) 0%, transparent 50%),
                    radial-gradient(circle at 80% 20%, rgba($blue, 0.08) 0%, transparent 50%),
                    radial-gradient(circle at 50% 80%, rgba($gold, 0.05) 0%, transparent 50%);
    }

    .hero-particles {
        position: absolute;
        inset: 0;
        pointer-events: none;
    }

    .hero-title {
        font-size: clamp(2.5rem, 6vw, 4.5rem);
        font-weight: 800;
        line-height: 1.1;
    }

    .typing-text {
        font-family: $font-family-code;
        font-size: clamp(1.2rem, 3vw, 2rem);
        font-weight: 600;

        .cursor {
            display: inline-block;
            width: 3px;
            height: 1.2em;
            background: $gold;
            margin-left: 4px;
            animation: blink 1s step-end infinite;
            vertical-align: middle;
        }
    }

    .hero-avatar {
        width: 300px;
        height: 300px;
        border-radius: 50%;
        object-fit: cover;
        border: 4px solid transparent;
        background-image: var(--gradient-accent);
        padding: 4px;
    }

    .hero-avatar-wrapper {
        position: relative;
        display: inline-block;

        &::before {
            content: '';
            position: absolute;
            inset: -10px;
            border-radius: 50%;
            background: var(--gradient-accent);
            opacity: 0.3;
            filter: blur(20px);
            z-index: -1;
        }
    }

    .scroll-down {
        position: absolute;
        bottom: 1.5rem;
        left: 50%;
        transform: translateX(-50%);
        color: $gold;
        font-size: 1.5rem;
        z-index: 10;

        i {
            animation: scrollDown 1.5s ease-in-out infinite;
        }
    }
}

// ---- Section Headings ----
.section-heading {
    margin-bottom: 3rem;

    .subtitle {
        display: inline-block;
        color: $gold;
        font-family: $font-family-code;
        font-size: 0.9rem;
        font-weight: 600;
        text-transform: uppercase;
        letter-spacing: 3px;
        margin-bottom: 0.5rem;
    }

    .title {
        font-size: clamp(2rem, 4vw, 3rem);
        font-weight: 800;
    }

    .divider {
        width: 60px;
        height: 4px;
        background: var(--gradient-gold);
        border-radius: 2px;
        margin: 1rem auto 0;
    }
}

// ---- About Section ----
.about-section {
    .about-image {
        position: relative;
        border-radius: $radius-lg;
        overflow: hidden;

        &::after {
            content: '';
            position: absolute;
            inset: 0;
            background: linear-gradient(135deg, rgba($gold, 0.1) 0%, transparent 50%);
        }
    }

    .info-item {
        display: flex;
        align-items: center;
        gap: 0.75rem;

        i {
            color: $gold;
            font-size: 1.25rem;
        }
    }
}

// ---- Statistics Section ----
.stat-card {
    text-align: center;
    padding: 2rem 1rem;

    .stat-icon {
        font-size: 2.5rem;
        color: $gold;
        margin-bottom: 1rem;
    }

    .stat-number {
        font-size: clamp(2rem, 4vw, 3.5rem);
        font-weight: 800;
        font-family: $font-family-heading;
        line-height: 1;
    }

    .stat-label {
        text-transform: uppercase;
        letter-spacing: 2px;
        font-size: 0.85rem;
        font-weight: 600;
        margin-top: 0.5rem;
    }
}

// ---- Services Section ----
.service-card {
    padding: 2rem;
    border-radius: $radius-md;
    height: 100%;
    transition: $transition-base;
    border: 1px solid transparent;

    &:hover {
        transform: translateY(-8px);
        box-shadow: $shadow-md;
    }

    .service-icon {
        width: 60px;
        height: 60px;
        display: flex;
        align-items: center;
        justify-content: center;
        border-radius: $radius-sm;
        font-size: 1.75rem;
        margin-bottom: 1.25rem;
        background: rgba($gold, 0.1);
        color: $gold;
    }

    h5 {
        font-weight: 700;
        margin-bottom: 0.75rem;
    }

    p {
        font-size: 0.925rem;
        line-height: 1.6;
    }
}

// ---- Skills Section ----
.skill-bar {
    margin-bottom: 1.5rem;

    .skill-info {
        display: flex;
        justify-content: space-between;
        margin-bottom: 0.5rem;

        .skill-name {
            font-weight: 600;
        }

        .skill-percent {
            color: $gold;
            font-weight: 700;
        }
    }

    .skill-progress {
        height: 8px;
        border-radius: 4px;
        overflow: hidden;

        .skill-progress-bar {
            height: 100%;
            border-radius: 4px;
            background: var(--gradient-gold);
            width: 0;
            transition: width 1.5s ease;
        }
    }
}

// ---- Projects Section ----
.project-filter {
    .filter-btn {
        padding: 0.5rem 1.5rem;
        border: 2px solid transparent;
        border-radius: $radius-pill;
        font-weight: 600;
        font-size: 0.9rem;
        transition: $transition-base;
        background: transparent;
        color: inherit;

        &:hover,
        &.active {
            background: var(--gradient-gold);
            color: #000;
        }
    }
}

.project-card {
    border-radius: $radius-md;
    overflow: hidden;
    transition: $transition-base;
    height: 100%;

    &:hover {
        transform: translateY(-8px);
        box-shadow: $shadow-lg;

        .project-overlay {
            opacity: 1;
        }

        .project-image img {
            transform: scale(1.1);
        }
    }

    .project-image {
        position: relative;
        overflow: hidden;
        aspect-ratio: 16 / 10;

        img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            transition: transform 0.5s ease;
        }
    }

    .project-overlay {
        position: absolute;
        inset: 0;
        background: rgba($dark-bg, 0.85);
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        opacity: 0;
        transition: opacity 0.4s ease;
        padding: 1.5rem;
        text-align: center;
    }

    .project-info {
        padding: 1.5rem;

        .project-category {
            color: $gold;
            font-size: 0.8rem;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        h5 {
            font-weight: 700;
            margin: 0.5rem 0;
        }
    }
}

// ---- Testimonials Section ----
.testimonial-card {
    padding: 2.5rem;
    border-radius: $radius-md;
    text-align: center;
    height: 100%;

    .testimonial-quote {
        font-size: 3rem;
        color: $gold;
        opacity: 0.3;
        line-height: 1;
        margin-bottom: 1rem;
    }

    .testimonial-content {
        font-size: 1.05rem;
        line-height: 1.8;
        font-style: italic;
        margin-bottom: 1.5rem;
    }

    .testimonial-author {
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 1rem;

        img {
            width: 60px;
            height: 60px;
            border-radius: 50%;
            object-fit: cover;
        }

        .author-info {
            text-align: left;

            h6 {
                font-weight: 700;
                margin: 0;
            }

            p {
                font-size: 0.85rem;
                margin: 0;
            }
        }
    }

    .testimonial-rating {
        color: $gold;
        font-size: 1.1rem;
        margin-bottom: 1rem;
    }
}

// ---- Contact Section ----
.contact-info-card {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 1.5rem;
    border-radius: $radius-md;
    transition: $transition-base;

    &:hover {
        transform: translateY(-4px);
        box-shadow: $shadow-md;
    }

    .contact-icon {
        width: 50px;
        height: 50px;
        display: flex;
        align-items: center;
        justify-content: center;
        border-radius: $radius-sm;
        font-size: 1.5rem;
        flex-shrink: 0;
        background: rgba($gold, 0.1);
        color: $gold;
    }

    .contact-label {
        font-size: 0.8rem;
        text-transform: uppercase;
        letter-spacing: 1px;
        font-weight: 600;
    }

    .contact-value {
        font-weight: 600;
        word-break: break-word;
    }
}

.whatsapp-btn {
    background: #25d366;
    color: #fff;
    border: none;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        background: #128c7e;
        color: #fff;
        transform: translateY(-2px);
        box-shadow: 0 4px 20px rgba(37, 211, 102, 0.3);
    }
}

// ---- Social Link (shared: hero + footer) ----
.social-link {
    width: 48px;
    height: 48px;
    padding: 0.6rem;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    font-size: 1.25rem;
    transition: $transition-base;

    &:hover {
        transform: translateY(-4px);
    }
}

// ---- Footer ----
.footer-section {
    padding: 4rem 0 2rem;

    .footer-brand {
        font-family: $font-family-heading;
        font-weight: 800;
        font-size: 1.5rem;
    }

    .footer-links {
        li {
            margin-bottom: 0.5rem;

            a {
                text-decoration: none;
                transition: $transition-fast;

                &:hover {
                    color: $gold;
                    padding-left: 5px;
                }
            }
        }
    }
}

// ---- Back to Top ----
.back-to-top {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    width: 50px;
    height: 50px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.25rem;
    z-index: 1000;
    opacity: 0;
    visibility: hidden;
    transition: $transition-base;
    border: none;

    &.visible {
        opacity: 1;
        visibility: visible;
    }

    &:hover {
        transform: translateY(-4px);
    }
}

// ---- Dark/Light Theme Toggle ----
.theme-toggle {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid transparent;
    font-size: 1.25rem;
    cursor: pointer;
    transition: $transition-base;
    background: transparent;

    &:hover {
        border-color: $gold;
    }
}

// ---- Light Theme Overrides ----
[data-bs-theme="light"] {
    .navbar-custom.scrolled {
        background: rgba($light-bg, 0.9) !important;
        box-shadow: $shadow-sm;
    }

    .hero-section .hero-bg-gradient {
        background: radial-gradient(circle at 20% 50%, rgba($gold, 0.06) 0%, transparent 50%),
                    radial-gradient(circle at 80% 20%, rgba($blue, 0.06) 0%, transparent 50%);
    }

    .service-card {
        background: $light-card;
        border-color: $light-border;

        &:hover {
            box-shadow: $shadow-md;
        }
    }

    .testimonial-card {
        background: $light-card;
        box-shadow: $shadow-sm;
    }

    .contact-info-card {
        background: $light-card;
        border: 1px solid $light-border;
    }

    .project-overlay {
        background: rgba($light-bg, 0.9);
    }

    .loading-screen {
        background: $light-bg;
    }

    ::-webkit-scrollbar-track {
        background: $light-bg-alt;
    }

    ::-webkit-scrollbar-thumb {
        background: $light-border;

        &:hover {
            background: $gold;
        }
    }
}

// ---- Dark Theme Overrides ----
[data-bs-theme="dark"] {
    .navbar-custom.scrolled {
        background: rgba($dark-bg, 0.9) !important;
        box-shadow: 0 2px 20px rgba(0, 0, 0, 0.5);
    }

    .service-card {
        background: $dark-card;
        border-color: $dark-border;
    }

    .testimonial-card {
        background: $dark-card;
        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
    }

    .contact-info-card {
        background: $dark-card;
        border: 1px solid $dark-border;
    }

    .stat-card {
        background: $dark-card-alt;
        border-radius: $radius-md;
    }

    .skill-bar .skill-progress {
        background: $dark-border;
    }

    .project-card {
        background: $dark-card;
        border: 1px solid $dark-border;
    }
}

// ===========================================
// Responsive — Mobile & Tablet
// ===========================================

// ---- Tablet (≤991px) ----
@media (max-width: 991.98px) {
    // Navbar mobile menu
    .navbar-custom {
        padding: 0.75rem 0;

        .navbar-collapse {
            background: rgba($dark-bg, 0.98);
            margin-top: 0.75rem;
            padding: 1.25rem;
            border-radius: $radius-md;
            border: 1px solid $dark-border;
            max-height: 75vh;
            overflow-y: auto;

            .navbar-nav {
                gap: 0.25rem !important;
            }

            .nav-link {
                padding: 0.75rem 1rem;
                border-radius: $radius-sm;

                &::after {
                    display: none;
                }
            }
        }
    }

    [data-bs-theme="light"] .navbar-custom .navbar-collapse {
        background: rgba($light-bg, 0.98);
        border-color: $light-border;
    }

    // Hero avatar
    .hero-section .hero-avatar {
        width: 220px;
        height: 220px;
    }

    // Testimonial padding
    .testimonial-card {
        padding: 1.75rem;
    }

    // Footer
    .footer-section {
        padding: 3rem 0 1.5rem;
    }
}

// ---- Mobile (≤767px) ----
@media (max-width: 767.98px) {
    // Navbar brand
    .navbar-custom {
        padding: 0.5rem 0;

        .container {
            padding-left: 0.75rem;
            padding-right: 0.75rem;
        }

        .navbar-brand {
            font-size: 1.1rem;
        }

        .navbar-toggler {
            padding: 0.2rem 0.4rem;

            i {
                font-size: 1.25rem;
            }
        }
    }

    // Hero section
    .hero-section {
        .hero-title {
            font-size: clamp(1.8rem, 8vw, 2.5rem);
        }

        .typing-text {
            font-size: clamp(1rem, 4vw, 1.3rem);
        }

        .hero-avatar {
            width: 170px;
            height: 170px;
        }

        .hero-avatar-wrapper::before {
            inset: -6px;
            filter: blur(14px);
        }

        .lead {
            font-size: 1rem;
        }

        .scroll-down {
            bottom: 0.75rem;
            font-size: 1.1rem;
        }
    }

    // Section headings
    .section-heading {
        margin-bottom: 2rem;

        .subtitle {
            font-size: 0.8rem;
            letter-spacing: 2px;
        }

        .title {
            font-size: clamp(1.5rem, 5vw, 2rem);
        }

        .divider {
            width: 45px;
        }
    }

    // Stats
    .stat-card {
        padding: 1.25rem 0.5rem;

        .stat-icon {
            font-size: 1.75rem;
        }

        .stat-number {
            font-size: clamp(1.5rem, 5vw, 2rem);
        }

        .stat-label {
            font-size: 0.7rem;
            letter-spacing: 1px;
        }
    }

    // Services
    .service-card {
        padding: 1.25rem;

        .service-icon {
            width: 48px;
            height: 48px;
            font-size: 1.4rem;
        }

        h5 {
            font-size: 1.05rem;
        }

        p {
            font-size: 0.875rem;
        }
    }

    // Skills
    .skill-bar {
        margin-bottom: 1rem;

        .skill-info {
            .skill-name {
                font-size: 0.875rem;
            }

            .skill-percent {
                font-size: 0.875rem;
            }
        }
    }

    // Projects
    .project-filter {
        gap: 0.5rem !important;

        .filter-btn {
            padding: 0.4rem 1rem;
            font-size: 0.825rem;
        }
    }

    .project-card {
        .project-overlay {
            padding: 1rem;

            h5 {
                font-size: 1rem;
            }

            p {
                font-size: 0.8rem;
            }
        }

        .project-info {
            padding: 1rem;

            h5 {
                font-size: 1rem;
            }
        }
    }

    // Testimonials
    .testimonial-card {
        padding: 1.25rem;

        .testimonial-quote {
            font-size: 2rem;
        }

        .testimonial-content {
            font-size: 0.95rem;
            line-height: 1.6;
        }

        .testimonial-author {
            flex-direction: column;
            gap: 0.75rem;

            .author-info {
                text-align: center;
            }
        }
    }

    // Contact
    .contact-info-card {
        padding: 1rem;
        gap: 0.75rem;

        .contact-icon {
            width: 40px;
            height: 40px;
            font-size: 1.25rem;
        }

        .contact-label {
            font-size: 0.7rem;
        }

        .contact-value {
            font-size: 0.875rem;
        }
    }

    // Footer
    .footer-section {
        padding: 2.5rem 0 1.5rem;

        .footer-brand {
            font-size: 1.25rem;
        }

        .social-link {
            width: 42px;
            height: 42px;
            padding: 0.5rem;
            font-size: 1.1rem;
        }
    }

    // Back to top
    .back-to-top {
        bottom: 1rem;
        right: 1rem;
        width: 42px;
        height: 42px;
        font-size: 1.1rem;
    }

    // Loading screen
    .loading-screen .loader-text {
        font-size: 1.25rem;
    }

    // Lightbox buttons
    #lightbox-close,
    #lightbox-prev,
    #lightbox-next {
        font-size: 1.5rem !important;
        margin: 0.75rem !important;
    }

    #lightbox-image {
        max-width: 92% !important;
    }
}

// ---- Small mobile (≤375px) ----
@media (max-width: 375px) {
    .hero-section {
        .hero-avatar {
            width: 140px;
            height: 140px;
        }

        .hero-title {
            font-size: 1.6rem;
        }
    }

    .stat-card {
        padding: 1rem 0.25rem;

        .stat-icon {
            font-size: 1.5rem;
        }

        .stat-label {
            font-size: 0.65rem;
        }
    }

    .service-card {
        padding: 1rem;
    }

    .testimonial-card {
        padding: 1rem;
    }

    .contact-info-card {
        padding: 0.75rem;
    }
}

// ---- Project Cost Calculator ----
.calculator-card {
    background: rgba($dark-card, 0.6);
    border: 1px solid $dark-border;
    border-radius: $radius-lg;
    padding: 2rem;
    backdrop-filter: blur(10px);
}

.calc-label {
    display: flex;
    align-items: center;
    font-weight: 600;
    font-size: 0.95rem;
    color: $dark-text;
    margin-bottom: 0.75rem;
}

.project-type-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
    gap: 0.75rem;
}

.project-type-btn {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    padding: 1.25rem 0.5rem;
    background: $dark-bg-alt;
    border: 2px solid $dark-border;
    border-radius: $radius-md;
    color: $dark-text-muted;
    cursor: pointer;
    transition: $transition-base;
    text-align: center;

    i {
        font-size: 1.5rem;
    }

    span {
        font-size: 0.85rem;
        font-weight: 500;
    }

    &:hover {
        border-color: rgba($gold, 0.5);
        color: $gold;
        background: rgba($gold, 0.05);
    }

    &.active {
        border-color: $gold;
        color: $gold;
        background: rgba($gold, 0.1);
        box-shadow: $shadow-gold;
    }
}

.page-count-badge {
    margin-left: auto;
    background: rgba($gold, 0.15);
    color: $gold;
    font-weight: 700;
    padding: 0.15rem 0.75rem;
    border-radius: $radius-pill;
    font-size: 0.9rem;
}

.calc-range {
    &::-webkit-slider-thumb {
        background: $gold;
    }

    &::-moz-range-thumb {
        background: $gold;
    }
}

.features-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 0.75rem;
}

.feature-chip {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
    background: $dark-bg-alt;
    border: 1px solid $dark-border;
    border-radius: $radius-sm;
    color: $dark-text-muted;
    cursor: pointer;
    transition: $transition-base;
    font-size: 0.875rem;
    user-select: none;

    i {
        font-size: 1.1rem;
    }

    input[type="checkbox"] {
        display: none;
    }

    &:hover {
        border-color: rgba($gold, 0.4);
        color: $dark-text;
    }

    &:has(input:checked) {
        border-color: $gold;
        color: $gold;
        background: rgba($gold, 0.08);
    }
}

.cost-display-panel {
    background: linear-gradient(135deg, rgba($gold, 0.05), rgba($blue, 0.05));
    border: 1px solid $dark-border;
    border-radius: $radius-md;
    padding: 2rem;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    position: sticky;
    top: 100px;
}

.cost-breakdown {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.cost-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.cost-label-text {
    color: $dark-text-muted;
    font-size: 0.9rem;
}

.cost-value {
    color: $dark-text;
    font-weight: 600;
    font-size: 0.95rem;
}

.total-cost-label {
    color: $dark-text-muted;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: 600;
}

.total-cost-amount {
    font-size: clamp(2rem, 5vw, 3rem);
    font-weight: 800;
    font-family: $font-family-heading;
    margin: 0.5rem 0 1rem;
}

.cost-note {
    font-size: 0.8rem;
    color: $dark-text-muted;
    line-height: 1.5;
    padding: 0.75rem;
    background: rgba($dark-bg, 0.5);
    border-radius: $radius-sm;
    border: 1px solid $dark-border;
}

@media (max-width: 767.98px) {
    .calculator-card {
        padding: 1.25rem;
    }

    .cost-display-panel {
        position: static;
        margin-top: 1rem;
    }

    .project-type-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .features-grid {
        grid-template-columns: 1fr;
    }
}

// ===========================================
// Abideen.dev — Animations
// ===========================================

// Keyframe Animations
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(40px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

